"""Render the three-panel reviewer report as Markdown.

Panel order is deliberate: evidence first, questions second, blind spots
last and never omitted. A report that cannot say "here is what I don't
know" should not be trusted with what it claims to know.
"""
from __future__ import annotations

from .schemas import CandidateReport, ClaimStatus

BANNER = (
    "> **⚠ ANOMALIES DETECTED. Review before reading further.** "
    "Flags are information for the reviewer, not a rejection: a human decides what they mean.\n"
)

HEADER = """# Candidate Evidence Report: `{cid}`

*Generated by the Candidate Evidence Workbench. This tool structures evidence
for a human reviewer. It does not score, rank, or recommend candidates, and
no decision should be attributed to it.*

Files examined: {files}
"""


def render(report: CandidateReport) -> str:
    parts = [HEADER.format(cid=report.candidate_id, files=", ".join(report.files_examined) or "none")]

    if report.anomalies:
        parts.append(BANNER)

    # Panel 1 — Evidence Map
    parts.append("## 1. Evidence Map\n")
    if not report.findings:
        parts.append("_No claims extracted (see Blind-Spot Report)._\n")
    else:
        parts.append("| Claim | Dimension | Status | Evidence / Rationale |")
        parts.append("|---|---|---|---|")
        for f in sorted(report.findings, key=lambda x: x.status.value):
            mark = "✅ evidenced" if f.status is ClaimStatus.EVIDENCED else "❓ unverified"
            where = f.evidence_pointer or f.rationale
            parts.append(f"| {f.claim.text} | {f.claim.rubric_dimension} | {mark} | {where} |")
        parts.append("")
        parts.append(
            f"**{len(report.evidenced)} evidenced · {len(report.unverified)} unverified.** "
            "Unverified does not mean untrue. It means the materials don't let a reviewer check it. "
            "Each unverified claim is converted to an interview question below.\n"
        )

    # Panel 2 — Interview Questions
    parts.append("## 2. Interview Questions (from unverified claims)\n")
    if not report.questions:
        parts.append("_None generated._\n")
    else:
        for i, q in enumerate(report.questions, 1):
            parts.append(f"{i}. {q.question}  \n   _probes: {q.probes_claim} · {q.rubric_dimension}_")
        parts.append("")

    # Anomalies (when present)
    if report.anomalies:
        parts.append("## ⚠ Anomaly Detail\n")
        for a in report.anomalies:
            parts.append(f"- **{a.kind}** (`{a.source_file}:{a.line}`): {a.explanation}")
            parts.append(f"  > `{a.excerpt}`")
        parts.append("")

    # Panel 3 — Blind-Spot Report (never omitted)
    parts.append("## 3. Blind-Spot Report: what this tool could NOT see\n")
    parts.append(
        "_Scope and limitations, stated per candidate. An evaluation aid that "
        "cannot name its blind spots invites over-trust in its visible output._\n"
    )
    for b in report.blind_spots:
        parts.append(f"- **{b.category}**: {b.detail}")
    parts.append("")

    return "\n".join(parts)
